// WA Automated Health Checks
const endpoints = [
  { name: 'erp', url: 'https://erp.insightpulseai.com/web/health' },
  { name: 'n8n', url: 'https://n8n.insightpulseai.com/healthz' },
  { name: 'superset', url: 'https://superset.insightpulseai.com/health' },
  { name: 'ocr', url: 'https://ocr.insightpulseai.com/health' },
  { name: 'auth', url: 'https://auth.insightpulseai.com/health' },
  { name: 'mcp', url: 'https://mcp.insightpulseai.com/health' },
  { name: 'plane', url: 'https://plane.insightpulseai.com/api/health' },
  { name: 'shelf', url: 'https://shelf.insightpulseai.com/health' },
  { name: 'crm', url: 'https://crm.insightpulseai.com/health' },
  { name: 'ops', url: 'https://ops.insightpulseai.com/health' },
];

const results = [];
for (const ep of endpoints) {
  try {
    const resp = await fetch(ep.url, { signal: AbortSignal.timeout(10000) });
    results.push({
      name: ep.name,
      status: resp.status,
      healthy: resp.status === 200,
      hsts: resp.headers.get('strict-transport-security') || 'missing',
    });
  } catch (e) {
    results.push({
      name: ep.name,
      status: 0,
      healthy: false,
      hsts: 'unreachable',
      error: e.message,
    });
  }
}

const healthy_count = results.filter(r => r.healthy).length;
const hsts_count = results.filter(r => r.hsts !== 'missing' && r.hsts !== 'unreachable').length;

return [{
  json: {
    timestamp: new Date().toISOString(),
    endpoints: results,
    summary: {
      total: endpoints.length,
      healthy: healthy_count,
      unhealthy: endpoints.length - healthy_count,
      hsts_enabled: hsts_count,
      health_score: Math.round((healthy_count / endpoints.length) * 5 * 10) / 10,
      tls_score: Math.round((hsts_count / endpoints.length) * 5 * 10) / 10,
    }
  }
}];

const data = $input.first().json;
const summary = data.summary;

// Compute overall WA score (simplified - health + TLS only for auto)
const pillars = [
  { name: 'Security (TLS/HSTS)', score: summary.tls_score, weight: 0.25 },
  { name: 'Reliability (Health)', score: summary.health_score, weight: 0.20 },
  { name: 'Operations', score: 3.0, weight: 0.20 },  // baseline pending full scorer
  { name: 'DevOps (DORA)', score: 3.0, weight: 0.20 },  // baseline pending full scorer
  { name: 'Governance', score: 3.0, weight: 0.15 },  // baseline pending full scorer
];

const overall = pillars.reduce((sum, p) => sum + p.score * p.weight, 0) /
  pillars.reduce((sum, p) => sum + p.weight, 0);

const unhealthy = data.endpoints.filter(e => !e.healthy);
const noHsts = data.endpoints.filter(e => e.hsts === 'missing');

return [{
  json: {
    overall_score: Math.round(overall * 100) / 100,
    pillars: pillars,
    high_risk: unhealthy.map(e => `${e.name}: unreachable (status ${e.status})`),
    warnings: noHsts.map(e => `${e.name}: HSTS missing`),
    report_date: data.timestamp,
  }
}];
